import React from "react";
import "./Banner.css";

import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay } from "swiper/modules";

import "swiper/css";

function Banner() {
  return (
    <div className="banner">
      <Swiper
        modules={[Autoplay]}
        autoplay={{ delay: 2000 }}
        spaceBetween={10}
        slidesPerView={1}
      >
        <SwiperSlide>
          <img
            src="https://images.unsplash.com/photo-1607083206968-13611e3d76db?q=80&w=1600&auto=format&fit=crop"
            alt="Sale Banner 1"
          />
        </SwiperSlide>

        <SwiperSlide>
          <img
            src="https://images.unsplash.com/photo-1607082349566-187342175e2f?q=80&w=1600&auto=format&fit=crop"
            alt="Sale Banner 2"
          />
        </SwiperSlide>

        <SwiperSlide>
          <img
            src="https://images.unsplash.com/photo-1607082350899-7e105aa886ae?q=80&w=1600&auto=format&fit=crop"
            alt="Sale Banner 3"
          />
        </SwiperSlide>
      </Swiper>
    </div>
  );
}

export default Banner;
